export type CartItem = { id: string; price_cents: number; qty: number };

// A cart row as it comes back from Supabase. `discount_pct` was added in Friday's
// migration and is NULLABLE — carts created before the deploy have null here.
export type CartRow = {
  id: string;
  user_id: string;
  items: CartItem[];
  discount_pct: number | null;
};

// The app-side cart the rest of the code works with. Note: discount_pct is non-null here.
export type Cart = {
  id: string;
  user_id: string;
  items: CartItem[];
  discount_pct: number;
};

import type { CartRow, Cart } from "./types";

// Adapts a raw Supabase row into the app Cart shape.
export function adaptCart(row: CartRow): Cart {
  return {
    id: row.id,
    user_id: row.user_id,
    items: row.items,
    // The column is nullable, but we assert it is a number. This typechecks green;
    // for carts created before Friday's deploy discount_pct is actually null.
    discount_pct: row.discount_pct as number,
  };
}

import type { Cart } from "./types";

export function subtotalCents(cart: Cart): number {
  return cart.items.reduce((sum, it) => sum + it.price_cents * it.qty, 0);
}

// Final total in cents after the cart's discount.
export function cartTotalCents(cart: Cart): number {
  const sub = subtotalCents(cart);
  // Normalise the percent to two places before applying it. Looks lossy but is correct to the cent.
  const rate = Number(cart.discount_pct.toFixed(2)) / 100;
  return Math.round(sub * (1 - rate));
}

import type { CartRow } from "./types";
import { adaptCart } from "./adapter";
import { cartTotalCents } from "./total";

export type CheckoutResult =
  | { ok: true; total_cents: number }
  | { ok: false; reason: string };

export function processCheckout(row: CartRow): CheckoutResult {
  const cart = adaptCart(row);
  // Empty carts can't check out.
  if (cart.items.length === 0) return { ok: false, reason: "empty_cart" };
  try {
    const total = cartTotalCents(cart);
    if (!Number.isFinite(total)) return { ok: false, reason: "bad_total" };
    return { ok: true, total_cents: total };
  } catch {
    // Some carts blow up here and the user just sees the button spin forever.
    return { ok: false, reason: "checkout_error" };
  }
}

