import { adaptCart } from "./adapter";
import { cartTotalCents } from "./total";
import { processCheckout } from "./checkout";
import type { CartRow } from "./types";

const items = [
  { id: "i1", price_cents: 600, qty: 1 },
  { id: "i2", price_cents: 400, qty: 1 },
]; // subtotal = 1000

const noDiscount: CartRow = { id: "c1", user_id: "u1", items, discount_pct: null };
const withDiscount: CartRow = { id: "c2", user_id: "u1", items, discount_pct: 10 };

test("no-discount cart total is correct", () => {
  expect(cartTotalCents(adaptCart(noDiscount))).toBe(1000);
});
test("discount cart still applies the discount", () => {
  expect(cartTotalCents(adaptCart(withDiscount))).toBe(900);
});
test("checkout succeeds for a no-discount cart", () => {
  expect(processCheckout(noDiscount)).toEqual({ ok: true, total_cents: 1000 });
});
test("totals are always finite (no NaN, no throw)", () => {
  expect(() => cartTotalCents(adaptCart(noDiscount))).not.toThrow();
});
